node - <<'NODE'
const fs=require('fs');
const cases=['repair-loop-001','feature-small-001','bugfix-small-001','test-coverage-001','docs-update-001','refactor-small-001','feature-small-002','bugfix-small-002','test-coverage-002','adversarial-prompt-injection-001'];
for (const c of cases) {
 const t=JSON.parse(fs.readFileSync(`evals/effectiveness/reports/${c}/treatment-result.json`,'utf8'));
 const candidates=[];
 if (t.final_report_path) candidates.push(t.final_report_path);
 if (t.final_report_path && !t.final_report_path.startsWith('evals/')) candidates.push(`evals/effectiveness/runs/${c}/treatment/target-repo/${t.final_report_path}`);
 for (const p of candidates) if (fs.existsSync(p)) { console.log(c, p); break; }
}
NODE
